const url = 'http://127.0.0.1:3000/api/base/%7BbaseId%7D/app/%7BappId%7D/files';
const options = {method: 'PATCH', headers: {Authorization: 'Bearer REPLACE_BEARER_TOKEN'}};

try {
  const response = await fetch(url, options);
  const data = await response.json();
  console.log(data);
} catch (error) {
  console.error(error);
}

const http = require('http');

const options = {
  method: 'PATCH',
  hostname: '127.0.0.1',
  port: '3000',
  path: '/api/base/%7BbaseId%7D/app/%7BappId%7D/files',
  headers: {
    Authorization: 'Bearer REPLACE_BEARER_TOKEN'
  }
};

const req = http.request(options, function (res) {
  const chunks = [];

  res.on('data', function (chunk) {
    chunks.push(chunk);
  });

  res.on('end', function () {
    const body = Buffer.concat(chunks);
    console.log(body.toString());
  });
});

req.end();

